"use strict";

const fs = require("fs");
const path = require("path");

const projectRoot = path.resolve(__dirname, "..");
const srcRoot = path.join(projectRoot, "src");
const outputDir = path.join(srcRoot, "renderer-bundles");

const entryPoints = [
  { name: "app", input: path.join(srcRoot, "app.js") },
  { name: "customer-ledger", input: path.join(srcRoot, "customer-ledger.js") },
  { name: "supplier-ledger", input: path.join(srcRoot, "supplier-ledger.js") },
  { name: "cashboxes", input: path.join(srcRoot, "cashboxes.js") },
  { name: "reconciliation-requests-manager", input: path.join(srcRoot, "reconciliation-requests-manager.js") }
];

const externalModules = {
  dexie: {
    globalName: "Dexie"
  }
};

function normalizePath(filePath) {
  return path.relative(projectRoot, filePath).replace(/\\/g, "/");
}

function ensureDirectory(dirPath) {
  fs.mkdirSync(dirPath, { recursive: true });
}

function resolveLocalModule(parentFile, request) {
  const basePath = path.resolve(path.dirname(parentFile), request);
  const candidates = [
    basePath,
    `${basePath}.js`,
    path.join(basePath, "index.js")
  ];

  for (const candidate of candidates) {
    if (fs.existsSync(candidate) && fs.statSync(candidate).isFile()) {
      return path.resolve(candidate);
    }
  }

  throw new Error(`Cannot resolve local module "${request}" from ${normalizePath(parentFile)}`);
}

function collectModuleGraph(entryFile) {
  const moduleMap = new Map();

  function visit(filePath) {
    const absolutePath = path.resolve(filePath);
    if (moduleMap.has(absolutePath)) {
      return;
    }

    const source = fs.readFileSync(absolutePath, "utf8").replace(/\r\n/g, "\n");
    const dependencyMap = {};
    const externals = new Set();
    const requirePattern = /require\s*\(\s*['"]([^'"]+)['"]\s*\)/g;
    let match = requirePattern.exec(source);

    while (match) {
      const request = match[1];
      if (request.startsWith(".")) {
        const resolved = resolveLocalModule(absolutePath, request);
        dependencyMap[request] = normalizePath(resolved);
        visit(resolved);
      } else if (externalModules[request]) {
        externals.add(request);
      } else {
        throw new Error(
          `Unsupported external module "${request}" in ${normalizePath(absolutePath)}`
        );
      }

      match = requirePattern.exec(source);
    }

    moduleMap.set(absolutePath, {
      id: normalizePath(absolutePath),
      source,
      dependencyMap,
      externals: Array.from(externals).sort()
    });
  }

  visit(entryFile);

  return Array.from(moduleMap.values()).sort((left, right) => left.id.localeCompare(right.id));
}

function indentSource(source, spaces) {
  const padding = " ".repeat(spaces);
  return source
    .split("\n")
    .map((line) => `${padding}${line}`)
    .join("\n");
}

function buildExternalLoadersSource() {
  const loaderEntries = Object.entries(externalModules).map(([moduleName, config]) => {
    return [
      `    ${JSON.stringify(moduleName)}: function loadExternalModule(globalObject) {`,
      `      const resolved = globalObject && globalObject[${JSON.stringify(config.globalName)}];`,
      "      if (typeof resolved === 'undefined') {",
      `        throw new Error("External module ${moduleName} is not available on globalThis.${config.globalName}");`,
      "      }",
      "      return resolved;",
      "    }"
    ].join("\n");
  });

  return loaderEntries.join(",\n");
}

function buildModulesSource(modules) {
  return modules.map((moduleRecord) => {
    return [
      `    ${JSON.stringify(moduleRecord.id)}: function rendererModule(module, exports, require) {`,
      indentSource(moduleRecord.source, 6),
      "    }"
    ].join("\n");
  }).join(",\n");
}

function buildResolutionMapSource(modules) {
  return modules.map((moduleRecord) => {
    return `    ${JSON.stringify(moduleRecord.id)}: ${JSON.stringify(moduleRecord.dependencyMap)}`;
  }).join(",\n");
}

function buildBundle(entryPoint) {
  const modules = collectModuleGraph(entryPoint.input);
  const entryModuleId = normalizePath(entryPoint.input);

  return [
    "/* eslint-disable */",
    `// Auto-generated renderer bundle for ${entryPoint.name}.`,
    "// Generated by scripts/build-renderer-bundles.js",
    "(function bootstrapRendererBundle(globalObject) {",
    "  const modules = {",
    buildModulesSource(modules),
    "  };",
    "",
    "  const resolutionMap = {",
    buildResolutionMapSource(modules),
    "  };",
    "",
    "  const externalLoaders = {",
    buildExternalLoadersSource(),
    "  };",
    "",
    "  const moduleCache = Object.create(null);",
    "",
    "  function requireModule(moduleId) {",
    "    if (moduleCache[moduleId]) {",
    "      return moduleCache[moduleId].exports;",
    "    }",
    "",
    "    const factory = modules[moduleId];",
    "    if (typeof factory !== 'function') {",
    "      throw new Error(`Unknown bundled module: ${moduleId}`);",
    "    }",
    "",
    "    const module = { exports: {} };",
    "    moduleCache[moduleId] = module;",
    "",
    "    function localRequire(request) {",
    "      if (externalLoaders[request]) {",
    "        return externalLoaders[request](globalObject);",
    "      }",
    "",
    "      const dependencies = resolutionMap[moduleId] || {};",
    "      const targetModuleId = dependencies[request];",
    "      if (!targetModuleId) {",
    "        throw new Error(`Cannot resolve ${request} from ${moduleId}`);",
    "      }",
    "",
    "      return requireModule(targetModuleId);",
    "    }",
    "",
    "    factory(module, module.exports, localRequire);",
    "    return module.exports;",
    "  }",
    "",
    `  requireModule(${JSON.stringify(entryModuleId)});`,
    "}(typeof globalThis !== 'undefined' ? globalThis : window));",
    ""
  ].join("\n");
}

function writeBundles() {
  ensureDirectory(outputDir);

  for (const entryPoint of entryPoints) {
    const outputPath = path.join(outputDir, `${entryPoint.name}.bundle.js`);
    const bundleSource = buildBundle(entryPoint);
    fs.writeFileSync(outputPath, bundleSource, "utf8");
    console.log(`Built ${normalizePath(outputPath)}`);
  }
}

writeBundles();
